For CSS-in-JS, template literal types validate property names and unit values. Define valid CSS properties as template literal unions and enforce unit suffixes:

type CSSUnit = 'px' | 'em' | 'rem' | '%' | 'vh' | 'vw';
type CSSValue = `${number}${CSSUnit}` | 'auto' | 'inherit';
type StyleProps = {
width?: CSSValue;
height?: CSSValue;
margin?: CSSValue;
padding?: CSSValue;
};
function createStyle(props: StyleProps): string {
return Object.entries(props)
.map(([key, value]) => `${key}: ${value};`)
.join(' ');
}
// Valid
createStyle({ width: '100px', margin: '2rem' });
// Error: '100' is not assignable to CSSValue
createStyle({ width: '100' });
// Error: 'widht' doesn't exist in StyleProps
createStyle({ widht: '100px' });

